ALTER SESSION SET CONTAINER=FREEPDB1;
ALTER USER sentineluser IDENTIFIED BY Sentinel2026;
ALTER USER sentineluser DEFAULT TABLESPACE USERS QUOTA UNLIMITED ON USERS;
CREATE TABLE sentineluser."Regioes" ("Id" NUMBER(10) GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, "Nome" NVARCHAR2(100) NOT NULL, "Pais" NVARCHAR2(80) NOT NULL, "NivelRisco" NVARCHAR2(30) NOT NULL);
CREATE TABLE sentineluser."Agentes" ("Id" NUMBER(10) GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, "Nome" NVARCHAR2(120) NOT NULL, "Email" NVARCHAR2(120) NOT NULL, "Cargo" NVARCHAR2(80) NOT NULL, "RegiaoId" NUMBER(10) NOT NULL, CONSTRAINT "FK_Agentes_Regioes" FOREIGN KEY ("RegiaoId") REFERENCES sentineluser."Regioes"("Id") ON DELETE CASCADE);
CREATE TABLE sentineluser."Ocorrencias" ("Id" NUMBER(10) GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, "Tipo" NVARCHAR2(100) NOT NULL, "Descricao" NVARCHAR2(500) NOT NULL, "DataOcorrencia" TIMESTAMP(7) NOT NULL, "Latitude" BINARY_DOUBLE NOT NULL, "Longitude" BINARY_DOUBLE NOT NULL, "RegiaoId" NUMBER(10) NOT NULL, CONSTRAINT "FK_Ocorrencias_Regioes" FOREIGN KEY ("RegiaoId") REFERENCES sentineluser."Regioes"("Id") ON DELETE CASCADE);
CREATE TABLE sentineluser."Alertas" ("Id" NUMBER(10) GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, "Tipo" NVARCHAR2(80) NOT NULL, "NivelRisco" NVARCHAR2(30) NOT NULL, "Descricao" NVARCHAR2(400) NOT NULL, "DataEmissao" TIMESTAMP(7) NOT NULL, "OcorrenciaId" NUMBER(10) NOT NULL, CONSTRAINT "FK_Alertas_Ocorrencias" FOREIGN KEY ("OcorrenciaId") REFERENCES sentineluser."Ocorrencias"("Id") ON DELETE CASCADE);
CREATE TABLE sentineluser."ImagensSatelite" ("Id" NUMBER(10) GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, "UrlImagem" NVARCHAR2(300) NOT NULL, "Fonte" NVARCHAR2(100) NOT NULL, "DataCaptura" TIMESTAMP(7) NOT NULL, "OcorrenciaId" NUMBER(10) NOT NULL, CONSTRAINT "FK_ImagensSatelite_Ocorrencias" FOREIGN KEY ("OcorrenciaId") REFERENCES sentineluser."Ocorrencias"("Id") ON DELETE CASCADE);
EXIT;
